class Solution(object):
    def findProductsOfElements(self, queries):
        """
        :type queries: List[List[int]]
        :rtype: List[int]
        """
        MOD = 10**5

        def get_position_in_big_array(num):
            """Get end position of num's powerful array in big_nums"""
            pos = 0
            for i in range(1, num + 1):
                bit_count = bin(i).count('1')
                pos += bit_count
            return pos - 1

        def get_bit_count(num):
            """Get number of set bits in num"""
            return bin(num).count('1')

        result = []

        for from_idx, to_idx, mod in queries:
            # Find which numbers and positions
            product = 1
            power_sum = 0

            # Binary search or direct computation for range
            current_pos = 0
            num = 1

            while current_pos <= to_idx:
                power_array = []
                for bit in range(50):
                    if num & (1 << bit):
                        power_array.append(bit)

                for power in power_array:
                    if current_pos >= from_idx and current_pos <= to_idx:
                        power_sum += power
                    current_pos += 1
                    if current_pos > to_idx:
                        break

                num += 1
                if current_pos > to_idx:
                    break

            # Compute 2^power_sum % mod
            ans = pow(2, power_sum, mod)
            result.append(ans)

        return result
